            datum_fields = set(datum)
            fields = len(candidate_fields.intersection(datum_fields))
            if fields > most_fields:
                best_match_index = index
                most_fields = fields
        elif record_type == 'float':
            best_match_index = index
            could_be_float = True
        else:
            best_match_index = index
            break

