def __wait_docker(self, instances):
    for _ in range(120):  # Use a numeric for loop instead of a while loop
        for instance in instances:
            instance.reload()
            if instance.attrs["State"]["Health"]["Status"] != "healthy":
                time.sleep(1)
                break
        else:
            # The else block is reached when all instances are healthy (no break inside the for loop)
            return True
    return False  # If 120 iterations have passed without all instances being healthy

