import os
import re

def balanced_braces(string):
    # Dummy implementation for balanced_braces, assuming it returns the balanced portion between { and }
    # For the purpose of this refactor.
    open_braces = 0
    balanced_str = ""
    for char in string:
        if char == '{':
            open_braces += 1
        elif char == '}':
            open_braces -= 1
        balanced_str += char
        if open_braces == 0:
            break
    return balanced_str

def remove_comments(string):
    # Dummy implementation for remove_comments, assuming it removes commented lines.
    return re.sub(r'//.*?$|/\*.*?\*/', '', string, flags=re.DOTALL | re.MULTILINE)

def __deps_list_gradle(list, project):
    # Read the contents of the build.gradle file:
    with open(os.path.join(project, 'build.gradle'), 'r') as f:
        gradle_content = f.read()

    # Removing comments from the Gradle file.
    gradle_content = remove_comments(gradle_content)

    # Extracting dependencies blocks and identifying internal dependencies.
    ideps = []
    for match in re.finditer(r'dependencies\s*\{', gradle_content):
        depends = balanced_braces(gradle_content[match.start():])
        ideps.extend(
            proj.replace(':', '/')
            for proj in re.findall(r'''compile project\(.*['"]:(.+)['"].*\)''', depends)
        )

    # If no internal dependencies are found, we can return.
    if not ideps:
        return

    # Starting the search for dependencies in parent directories (up to two levels).
    path = project
    for i in range(1, 3):
        path = os.path.abspath(os.path.join(path, os.path.pardir))
        deps = []

        # Attempting to resolve paths to the dependencies.
        for idep in ideps:
            dep = os.path.join(path, idep)
            if not os.path.isdir(dep):
                break
            deps.append(dep)
        else:
            # Loop completed without a break, meaning all dependencies were found.
            for dep in deps:
                __deps_list_gradle(list, dep)  # Recursion for the found dependency
                if dep not in list:
                    list.append(dep)
            break   # Stop searching after successfully finding dependencies

