def filter_noun_chunks(
    chunks, exclude_pronouns=False, exclude_query=None, exact_match=False
):
    # Step 1: Filter pronouns if `exclude_pronouns` is True
    if exclude_pronouns:
        chunks = [
            np
            for np in chunks
            if (np.lemma_ != "-PRON-" and not all(tok.pos_ == "PRON" for tok in np))
        ]

    # Step 2: Filter based on exclude_query if provided
    if exclude_query is not None:
        excl_txt = [exclude_query.lower()]
        filtered_chunks = []
        for chunk in chunks:
            lower_chunk = chunk.text.lower()

            for excl in excl_txt:
                # Match logic, exact vs partial
                if (
                    not exact_match and (lower_chunk in excl or excl in lower_chunk)
                ) or lower_chunk == excl:
                    # Found match, do not append the chunk
                    break
            else:
                # No match was found in excl_txt, append the chunk
                filtered_chunks.append(chunk)

        chunks = filtered_chunks

    return chunks

