                #     print('to_add', to_add)
                # print('p_out', p_out)
                # print('p_in', p_in)
                # print('out_ps', out_ps)
                # print('polygon_n', polygon_n)
                polygon_n.append(p)
                p_out = None
                out_ps = []
        else:
