def op_notif(stack, items):
    if len(stack) < 1:
        return False
    # go through and re-make the items array based on the top stack element
    true_items = []
    false_items = []
    current_array = true_items
    num_endifs_needed = 1

    # Use a loop-else idiom here
    while len(items) > 0:
        item = items.pop(0)
        if item in (99, 100):
            # nested if, we have to go another endif
            num_endifs_needed += 1
            current_array.append(item)
        elif num_endifs_needed == 1 and item == 103:
            current_array = false_items
        elif item == 104:
            if num_endifs_needed == 1:
                break  # if found, break the while loop
            else:
                num_endifs_needed -= 1
                current_array.append(item)
        else:
            current_array.append(item)
    else:
        # Executed if the loop is not broken (i.e., if 104 is not found)
        return False

    # Loop was broken by finding the item `104`
    element = stack.pop()
    if decode_num(element) == 0:
        items[:0] = true_items
    else:
        items[:0] = false_items
    return True

